mapper.select:
SELECT COUNT(*) FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO

  W.USEYN = 1
  AND (W.PAR_WORKORDNO IS NOT NULL AND LTRIM(RTRIM(W.PAR_WORKORDNO)) != '')
  AND W.ORDSTATE != 'DONE'
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND W.LINECD = #{line_cd}
  AND W.PROCESSCD = #{process_cd}
  AND W.WORKORDNO LIKE #{workord_no}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

SELECT W.SHIFT, W.WORKORDNO, W.LINECD, W.PROCESSCD,
       W.PARTNO AS PROC_PARTNO, G.PARTNM AS PROC_PARTNM, G.STANDARD AS PROC_STANDARD,
       W.ORDpriority, W.ORDQTY, G.UNIT, W.ORDSTATE,
       ISNULL(PW.PARTNO, W.PARTNO) AS PARTNO, 
       ISNULL(PG.PARTNM, G.PARTNM) AS PARTNM, 
       ISNULL(L.LOTNO, '') AS LOTNO, W.REMARK
FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO
/* 상위 작업지시 조인하여 상위 품번 정보 획득 */
LEFT JOIN TBL_PROD_WORKORDER PW ON W.PAR_WORKORDNO = PW.WORKORDNO
LEFT JOIN TBL_COM_GOODS PG ON PW.PARTNO = PG.PARTNO
/* 생산된 LOT 정보 조인 (최근 생성된 LOT 하나 표시) */
LEFT JOIN (
    SELECT WORKORDNO, MAX(LOTNO) AS LOTNO
    FROM TBL_PROD_LOTSTATE
    WHERE LOTSTATE != 'CANCELED'
    GROUP BY WORKORDNO
) L ON W.WORKORDNO = L.WORKORDNO

  W.USEYN = 1
  AND (W.PAR_WORKORDNO IS NOT NULL AND LTRIM(RTRIM(W.PAR_WORKORDNO)) != '')
  AND W.ORDSTATE != 'DONE'
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND W.LINECD = #{line_cd}
  AND W.PROCESSCD = #{process_cd}
  AND W.WORKORDNO LIKE #{workord_no}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

ORDER BY W.ORDDATE DESC, W.WORKORDNO DESC
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

/* 1. 현재 작업지시에 투입된 내역 (INPUT) */ SELECT H.LOTNO, S.PARTNO, G.PARTNM, G.STANDARD, G.UNIT, ABS(H.QTY) AS INPUT_QTY, ISNULL(B.REQQTY, 0) AS NEED_QTY, ABS(H.QTY) AS STOCK_QTY, 'INPUT' AS RECORD_GUBUN, ISNULL(L.LOCATIONNAME, S.LOCATIONCODE) AS LOCATIONNAME FROM TBL_PROD_STOCK_HISTORY H JOIN TBL_PROD_LOTSTATE S ON H.LOTNO = S.LOTNO JOIN TBL_COM_GOODS G ON S.PARTNO = G.PARTNO JOIN TBL_PROD_WORKORDER W ON H.REF_NO = W.WORKORDNO LEFT JOIN ( SELECT PAR_PARTNO, CHILD_PARTNO, SUM(REQQTY) AS REQQTY FROM TBL_COM_BOM WHERE USEYN = 1 GROUP BY PAR_PARTNO, CHILD_PARTNO ) B ON W.PARTNO = B.PAR_PARTNO AND S.PARTNO = B.CHILD_PARTNO LEFT JOIN TBL_COM_LOCATION L ON S.LOCATIONCODE = L.LOCATIONCODE WHERE H.REF_NO = #{WORKORDNO} AND H.STOCKCHANGEGUBUN = '투입'
UNION ALL
/* 2. 아직 투입되지 않은 창고의 가용 재고 (STOCK) */ SELECT S.LOTNO, S.PARTNO, G.PARTNM, G.STANDARD, G.UNIT, 0 AS INPUT_QTY, B.REQQTY AS NEED_QTY, S.LOTQTY AS STOCK_QTY, 'STOCK' AS RECORD_GUBUN, ISNULL(L.LOCATIONNAME, S.LOCATIONCODE) AS LOCATIONNAME FROM TBL_PROD_WORKORDER W JOIN ( SELECT PAR_PARTNO, CHILD_PARTNO, SUM(REQQTY) AS REQQTY FROM TBL_COM_BOM WHERE USEYN = 1 GROUP BY PAR_PARTNO, CHILD_PARTNO ) B ON W.PARTNO = B.PAR_PARTNO JOIN TBL_PROD_LOTSTATE S ON B.CHILD_PARTNO = S.PARTNO JOIN TBL_COM_GOODS G ON S.PARTNO = G.PARTNO LEFT JOIN TBL_COM_LOCATION L ON S.LOCATIONCODE = L.LOCATIONCODE WHERE W.WORKORDNO = #{WORKORDNO} AND S.LOTQTY > 0 AND S.LOTSTATE IN ('GOOD', 'CREATED') /* 현재 작지에 아직 투입되지 않은 LOT만 노출 */ AND NOT EXISTS ( SELECT 1 FROM TBL_PROD_STOCK_HISTORY H2 WHERE H2.REF_NO = #{WORKORDNO} AND H2.LOTNO = S.LOTNO AND H2.STOCKCHANGEGUBUN = '투입' ) ORDER BY RECORD_GUBUN, PARTNO, LOTNO

